    public static function getMenuGroups()
    {
        $user = request()->user();
        $role = $user ? $user->role : null;

        return match ($role) {
            'superadmin' => self::getSuperadminMenu(),
            'admin'      => self::getAdminMenu(),
            'officer'    => self::getOfficerMenu(),
            default      => [],
        };
    }

